// Initialize State — reads publish log + ramp-up state from static workflow data
const staticData = $getWorkflowStaticData('global');

// Seed initial values on first run
if (!staticData.launch_date) {
  staticData.launch_date = new Date().toISOString().split('T')[0];
}
if (!staticData.publish_log) {
  staticData.publish_log = {};
}

// Ramp-up phase: weeks 1-8 gate which sites can publish
const launchDate = new Date(staticData.launch_date);
const daysSinceLaunch = Math.floor((Date.now() - launchDate.getTime()) / (1000 * 60 * 60 * 24));
const weeksSinceLaunch = Math.max(1, Math.ceil(daysSinceLaunch / 7));
const ramp_up_active = weeksSinceLaunch <= 8;

// Preserve override from incoming request body (e.g. manual force-run)
const body = $json.body || $json || {};
const requested_sites = body.site_ids || null;
const force = body.force === true;

return [{
  json: {
    launch_date: staticData.launch_date,
    days_since_launch: daysSinceLaunch,
    weeks_since_launch: weeksSinceLaunch,
    ramp_up_active,
    publish_log: staticData.publish_log,
    requested_sites,
    force,
    seo_intel: staticData.seo_intel || {},
    media_queue: staticData.media_queue || [],
    research_queue: staticData.research_queue || [],
    content_exec_count: staticData.content_exec_count || 0,
  }
}];

// Evaluate Site Eligibility — ramp-up schedule + per-site cadence + publish day check
const {
  publish_log, weeks_since_launch, ramp_up_active, requested_sites, force
} = $json;

// Full-production minimum days between publishes per site
const MIN_INTERVALS = {
  sinabarimd:             7,   // weekly
  sinabari_net:           3,   // twice/week (Tue + Fri)
  drsinabari:             14,  // bi-weekly (long-form editorial)
  sinabariplasticsurgery: 7,   // weekly
};

// Designated publish day per site (0=Sun, 1=Mon, 2=Tue, 3=Wed, 4=Thu)
// Mon 09:00 PST · Tue 10:00 PST · Wed 11:00 PST · Thu 14:00 PST
const PUBLISH_DAYS = {
  sinabarimd:             1,
  sinabari_net:           2,
  drsinabari:             4,
  sinabariplasticsurgery: 3,
};

// Ramp-up site allowlist by week (week 6+ = all four sites)
const RAMP_SCHEDULE = {
  1: ['sinabarimd'],
  2: ['sinabarimd'],
  3: ['sinabarimd', 'sinabari_net'],
  4: ['sinabarimd', 'sinabari_net'],
  5: ['sinabarimd', 'sinabari_net', 'drsinabari'],
  6: ['sinabarimd', 'sinabari_net', 'drsinabari', 'sinabariplasticsurgery'],
};

const ALL_SITES = Object.keys(MIN_INTERVALS);
const now = Date.now();
const todayDay = new Date().getDay(); // 0=Sun ... 6=Sat

// Determine candidate list
let candidates;
if (Array.isArray(requested_sites) && requested_sites.length > 0) {
  // Operator override: bypass day-of-week check, respect cadence only
  candidates = requested_sites.filter(s => ALL_SITES.includes(s));
} else if (ramp_up_active) {
  const week = Math.min(weeks_since_launch, 6);
  const rampCandidates = RAMP_SCHEDULE[week] || ['sinabarimd'];
  // Still respect publish day during ramp
  candidates = rampCandidates.filter(s => PUBLISH_DAYS[s] === todayDay);
} else {
  // Full production: only the site(s) whose day it is
  candidates = ALL_SITES.filter(s => PUBLISH_DAYS[s] === todayDay);
}

// Check per-site cadence (skip if force=true)
const eligible = [];
const skipped = [];

for (const site_id of candidates) {
  if (force) {
    eligible.push(site_id);
    continue;
  }
  const lastPublish = publish_log[site_id];
  if (!lastPublish) {
    eligible.push(site_id);
    continue;
  }
  const daysSince = (now - new Date(lastPublish).getTime()) / (1000 * 60 * 60 * 24);
  const minDays = MIN_INTERVALS[site_id];
  if (daysSince >= minDays) {
    eligible.push(site_id);
  } else {
    skipped.push({ site_id, days_since: Math.floor(daysSince), min_days: minDays, next_eligible_in: Math.ceil(minDays - daysSince) });
  }
}

return [{
  json: {
    ...$json,
    eligible_sites: eligible,
    skipped_sites: skipped,
    eligible_count: eligible.length,
    today_day: todayDay,
  }
}];

// Assemble Briefs — check for approved drafts first, then generate new
const upstream = $('Evaluate Site Eligibility').first().json;
const {
  eligible_sites, seo_intel, media_queue, research_queue, content_exec_count
} = upstream;

// Get approved drafts from the Fetch Approved Drafts response
const draftsResponse = $json;
const approvedDrafts = draftsResponse.approved_drafts || [];

const OPENING_TYPES = ['narrative', 'question', 'direct_statement', 'data_point'];
const BASE_WORD_COUNTS = {
  sinabarimd: 750, sinabari_net: 1200,
  drsinabari: 1500, sinabariplasticsurgery: 900,
};

const briefs = eligible_sites.map(site_id => {
  // Check if there's an approved draft waiting for this site
  const approvedDraft = approvedDrafts.find(d => d.site_id === site_id);

  if (approvedDraft) {
    return {
      action: 'auto_publish',
      site_id,
      draft_id: approvedDraft.draft_id,
    };
  }

  // No approved draft — generate new content
  const researchBrief = (research_queue || [])
    .find(r => r.site_id === site_id && !r.consumed) || null;
  const mediaBrief = (media_queue || [])
    .filter(m => m.target_site_id === site_id && !m.consumed)
    .slice(0, 3);

  return {
    action: 'generate',
    site_id,
    seo_context: seo_intel?.latest_brief || null,
    media_context: mediaBrief,
    research_brief: researchBrief,
    variation_seed: {
      opening_type: OPENING_TYPES[content_exec_count % 4],
      target_word_count: Math.round((BASE_WORD_COUNTS[site_id] || 900) * (0.85 + Math.random() * 0.3)),
      heading_depth: content_exec_count % 2 === 0 ? 2 : 3,
    },
  };
});

return briefs.map(brief => ({ json: brief }));

// Increment exec count after Content Generator dispatch (draft stored, not yet published)
const staticData = $getWorkflowStaticData('global');
staticData.content_exec_count = (staticData.content_exec_count || 0) + 1;

// Pass through for batch loop
return [{ json: { ...$json, dispatched: true } }];

// No Eligible Sites — build response for when nothing qualifies
return [{
  json: {
    summary: 'No sites eligible for publishing this run',
    dispatched: [],
    skipped: $json.skipped_sites || [],
    eligible_count: 0,
    run_at: new Date().toISOString(),
  }
}];

// Collect Results — aggregate all dispatched sites into summary
const items = $input.all();

const dispatched = items
  .filter(i => i.json.publish_logged)
  .map(i => ({ site_id: i.json.publish_logged, publish_date: i.json.publish_date }));

const skipped = items[0]?.json?._state?.skipped_sites || [];
const eligible_count = items[0]?.json?._state?.eligible_count || dispatched.length;

return [{
  json: {
    summary: dispatched.length > 0
      ? `${dispatched.length} site(s) dispatched for publishing`
      : 'No eligible sites this run',
    dispatched,
    skipped,
    eligible_count,
    run_at: new Date().toISOString(),
  }
}];

// Store Research Brief — adds incoming brief to research_queue in static data
const body = $json.body || $json;
const brief = body.brief || body;

if (!brief || !brief.site_id) {
  return [{ json: { success: false, error: 'Missing required field: site_id' } }];
}

const staticData = $getWorkflowStaticData('global');
const queue = staticData.research_queue || [];

// Remove any existing unconsumed brief for the same site (replace with latest)
const filtered = queue.filter(b => !(b.site_id === brief.site_id && !b.consumed));
filtered.push({ ...brief, consumed: false, queued_at: new Date().toISOString() });
staticData.research_queue = filtered;

return [{ json: {
  success: true,
  site_id: brief.site_id,
  topic: brief.recommended_topic || brief.approved_topic || '(no topic)',
  queue_depth: filtered.filter(b => !b.consumed).length,
} }];

// Update Publish Log — called by Content Publisher after successful deploy
const body = $json.body || $json;
const site_id = body.site_id;
const publish_date = body.publish_date || new Date().toISOString().split('T')[0];

if (!site_id) {
  return [{ json: { success: false, error: 'site_id required' } }];
}

const staticData = $getWorkflowStaticData('global');
if (!staticData.publish_log) staticData.publish_log = {};
staticData.publish_log[site_id] = publish_date;

return [{ json: {
  success: true,
  site_id,
  publish_date,
  publish_log: staticData.publish_log,
} }];

const staticData = $getWorkflowStaticData('global');
const publish_log = staticData.publish_log || {};
const launch_date = staticData.launch_date || null;
const ramp_up_active = staticData.ramp_up_active !== false;

// Compute next scheduled cron for each site
const CRON_SCHEDULE = {
  sinabarimd:             { days: [1], hour: 9, tz: 'PST' },
  sinabari_net:           { days: [2, 5], hour: 10, tz: 'PST' },
  sinabariplasticsurgery: { days: [3], hour: 11, tz: 'PST' },
  drsinabari:             { days: [4], hour: 14, tz: 'PST' },
};

const MIN_INTERVALS = {
  sinabarimd: 7, sinabari_net: 3,
  sinabariplasticsurgery: 7, drsinabari: 14,
};

const now = new Date();
const schedule = {};

for (const [site_id, cron] of Object.entries(CRON_SCHEDULE)) {
  if (cron.suspended) {
    schedule[site_id] = { next_cron: null, status: 'suspended' };
    continue;
  }

  const lastPub = publish_log[site_id] ? new Date(publish_log[site_id]) : null;
  const minDays = MIN_INTERVALS[site_id];
  const earliestEligible = lastPub 
    ? new Date(lastPub.getTime() + minDays * 24 * 60 * 60 * 1000) 
    : now;

  // Find next cron day (PST = UTC-7 roughly, but use UTC offset of 7h)
  let nextCron = null;
  for (let dayOffset = 0; dayOffset <= 14; dayOffset++) {
    const candidate = new Date(now);
    candidate.setDate(candidate.getDate() + dayOffset);
    const dayOfWeek = candidate.getDay(); // 0=Sun
    if (cron.days.includes(dayOfWeek === 0 ? 7 : dayOfWeek)) {
      candidate.setUTCHours(cron.hour + 7, 0, 0, 0); // PST→UTC rough
      if (candidate > now && candidate >= earliestEligible) {
        nextCron = candidate.toISOString();
        break;
      }
    }
  }

  schedule[site_id] = {
    last_published: publish_log[site_id] || null,
    min_interval_days: minDays,
    earliest_eligible: earliestEligible.toISOString(),
    next_cron: nextCron,
    cron_days: cron.days,
    cron_hour_pst: cron.hour,
  };
}

return [{ json: {
  publish_log,
  launch_date,
  ramp_up_active,
  schedule,
} }];

const body = $json.body || $json;
const staticData = $getWorkflowStaticData('global');

if (!staticData.seo_intel) staticData.seo_intel = {};
staticData.seo_intel.latest_brief = body;
staticData.seo_intel.updated_at = new Date().toISOString();

return [{ json: { success: true, research_date: body.research_date, summary: body.summary } }];

const body = $json.body || $json;
const incomingItems = body.media_items || [];
const staticData = $getWorkflowStaticData('global');
staticData.media_queue = incomingItems;
return [{ json: { success: true, queue_depth: incomingItems.length, updated_at: new Date().toISOString() } }];

const staticData = $getWorkflowStaticData('global');
const spotlight = staticData.spotlight || null;
const history = (staticData.spotlight_history || []).map(h => ({
  slug: h.slug,
  title: h.title,
  excerpt: h.excerpt,
  publish_date: h.publish_date,
  article_html: h.article_html || null,
}));
return [{ json: { spotlight, history } }];

const staticData = $getWorkflowStaticData('global');
const body = $json.body || $json;
const { title, excerpt, slug, article_html, publish_date } = body;

if (!title || !slug) {
  return [{ json: { success: false, error: 'Required: title, slug' } }];
}

// Archive current spotlight to history before replacing
if (!staticData.spotlight_history) staticData.spotlight_history = [];
if (staticData.spotlight && staticData.spotlight.slug) {
  const prev = staticData.spotlight;
  // Only add if not already in history
  if (!staticData.spotlight_history.some(h => h.slug === prev.slug)) {
    staticData.spotlight_history.push({
      slug: prev.slug,
      title: prev.title,
      excerpt: prev.excerpt || '',
      publish_date: prev.publish_date || '',
      article_html: prev.article_html || null,
      archived_at: new Date().toISOString(),
    });
  }
}

staticData.spotlight = {
  title,
  excerpt: excerpt || '',
  slug,
  article_path: 'articles/' + slug + '.html',
  article_html: article_html || null,
  publish_date: publish_date || new Date().toISOString().split('T')[0],
  set_at: new Date().toISOString(),
};

return [{ json: {
  success: true,
  spotlight: { ...staticData.spotlight, article_html: '(stored, ' + (article_html||'').length + ' chars)' },
  history_count: staticData.spotlight_history.length,
} }];

const staticData = $getWorkflowStaticData('global');
const campaign = staticData.spotlight_campaign || null;
return [{ json: { campaign } }];

const staticData = $getWorkflowStaticData('global');
const body = $json.body || $json;
const { title, slug, article_url, tasks } = body;

if (!title || !tasks || !Array.isArray(tasks)) {
  return [{ json: { success: false, error: 'Required: title, tasks[]' } }];
}

staticData.spotlight_campaign = {
  title,
  slug: slug || '',
  article_url: article_url || '',
  launched_at: new Date().toISOString(),
  tasks: tasks.map((t, i) => ({
    ...t,
    task_id: 'sc_' + Date.now() + '_' + i,
    status: t.status || 'pending',
    spotlight: true,
  })),
};

return [{ json: { success: true, total_tasks: tasks.length, campaign_title: title } }];

const staticData = $getWorkflowStaticData('global');
const body = $json.body || $json;
const { task_id, action } = body;

if (!staticData.spotlight_campaign || !task_id) {
  return [{ json: { success: false, error: 'No campaign or task_id' } }];
}

const task = staticData.spotlight_campaign.tasks.find(t => t.task_id === task_id);
if (!task) return [{ json: { success: false, error: 'Task not found' } }];

task.status = action || 'completed';
task.completed_at = new Date().toISOString();

return [{ json: { success: true, task_id, status: task.status } }];

const staticData = $getWorkflowStaticData('global');
const spotlight = staticData.spotlight;

if (!spotlight || !spotlight.title) {
  return [{ json: { skip: true, reason: 'No spotlight data' } }];
}

// Strip HTML from article to get plain text for the prompt
const html = spotlight.article_html || '';
const plainText = html
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<[^>]+>/g, '\n')
  .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
  .replace(/&nbsp;/g, ' ').replace(/&#39;/g, "'").replace(/&quot;/g, '"')
  .split('\n').map(l => l.trim()).filter(l => l).join('\n')
  .substring(0, 8000);

const articleUrl = 'https://sinabarimd.com/' + spotlight.article_path;
const githubUrl = 'https://github.com/sinabarimd/reputation-engine';

const prompt = `You are a social media content strategist for Dr. Sina Bari, MD -- a Stanford-trained plastic surgeon and healthcare AI executive.

Given the following spotlight article, generate a 15-task social media campaign. Each task is a ready-to-post piece of content adapted for a specific platform.

ARTICLE TITLE: ${spotlight.title}
ARTICLE EXCERPT: ${spotlight.excerpt}
ARTICLE URL: ${articleUrl}
GITHUB REPO: ${githubUrl}

ARTICLE TEXT (first 8000 chars):
${plainText}

CAMPAIGN SCHEDULE (15 tasks across 3 weeks):

Day 1: LinkedIn - article_post (professional announcement, 150-200 words, hashtags)
Day 2: Twitter/X - thread (5-tweet thread, key insights, link at end)
Day 3: Medium - article_repost (500-word excerpt adapted for Medium audience, note to set canonical URL to ${articleUrl}, include GitHub link at end)
Day 4: Facebook - share (conversational tone, 100-150 words, link)
Day 5: WordPress (sinabarimd0) - excerpt_post (300-word excerpt with backlink)
Day 6: Quora - answer (find relevant questions about personal SEO/reputation/AI agents, write 200-word answer referencing the article)
Day 7: WordPress (sinabarimd) - excerpt_post (300-word different angle excerpt)
Day 8: Tumblr - reflection (200-word personal reflection on why you built this)
Day 9: LinkedIn - follow_up (follow-up post referencing response to original, 100-150 words)
Day 10: YouTube - description_update (update channel description to reference the article/project)
Day 11: Twitter/X - insight (single tweet with one surprising finding/stat from the article)
Day 12: Strikingly - content_update (section update text, 100 words + link)
Day 13: Instagram - story_or_post (caption for graphic/screenshot, 100 words)
Day 14: LinkedIn - featured_update (instructions to add article to Featured section + GitHub repo)
Day 15: Medium - follow_up (400-word companion piece: "3 Things I Learned Building an AI Reputation Engine")

RULES:
- Write from Dr. Bari's first-person perspective
- Never claim board certification
- Never use em-dashes (use -- instead)
- Every post must include a link back to sinabarimd.com or the article URL
- Adapt tone and format to each platform's conventions
- LinkedIn: professional but not stiff, use line breaks
- Twitter: concise, punchy, use thread format where specified
- Medium: longer form, editorial quality, always mention canonical URL
- Facebook: conversational, personal
- Quora: helpful expert answering a real question
- Instagram: visual-first caption style
- For platform updates (YouTube, Strikingly, LinkedIn Featured): provide the exact text/instructions to paste

Return ONLY a JSON array of 15 objects, each with these exact fields:
{
  "platform_id": "linkedin|twitter|medium|facebook|wordpress0|quora|wordpress_sinabarimd|tumblr|youtube|mystrikingly|instagram",
  "platform_name": "Display Name",
  "post_type": "article_post|thread|article_repost|share|excerpt_post|answer|reflection|follow_up|description_update|insight|content_update|story_or_post|featured_update",
  "content": "The full ready-to-post text"
}

Return ONLY the JSON array, no markdown fencing, no explanation.`;

const requestBody = JSON.stringify({
  model: 'openclaw',
  input: prompt,
});

return [{ json: { skip: false, openclaw_request_body: requestBody, articleUrl, spotlight_title: spotlight.title, spotlight_slug: spotlight.slug } }];

const staticData = $getWorkflowStaticData('global');
const spotlight = staticData.spotlight;
const upstream = $('Prepare Campaign Prompt').first().json;

// Parse OpenClaw response
let responseText = '';
const output = $json.output || [];
for (const item of output) {
  if (item.type === 'message' && item.content) {
    for (const block of item.content) {
      if (block.type === 'output_text') {
        responseText += block.text;
      }
    }
  }
}

// Clean up response - strip markdown fencing if present
responseText = responseText.trim();
if (responseText.startsWith('```')) {
  responseText = responseText.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
}

let tasks;
try {
  tasks = JSON.parse(responseText);
} catch (e) {
  return [{ json: { success: false, error: 'Failed to parse OpenClaw response: ' + e.message, raw: responseText.substring(0, 500) } }];
}

if (!Array.isArray(tasks) || tasks.length === 0) {
  return [{ json: { success: false, error: 'OpenClaw returned empty or non-array', raw: responseText.substring(0, 500) } }];
}

// Build the campaign with dates spread across 15 days starting tomorrow
const startDate = new Date();
startDate.setDate(startDate.getDate() + 1);

const campaignTasks = tasks.map((t, i) => {
  const taskDate = new Date(startDate);
  taskDate.setDate(taskDate.getDate() + i);
  const dateStr = taskDate.toISOString().split('T')[0];

  return {
    date: dateStr,
    platform_id: t.platform_id || 'unknown',
    platform_name: t.platform_name || t.platform_id || 'Unknown',
    post_type: t.post_type || 'post',
    content: t.content || '',
    link: upstream.articleUrl || '',
    task_id: 'sc_' + Date.now() + '_' + i,
    status: 'pending',
    spotlight: true,
  };
});

// Store in staticData
staticData.spotlight_campaign = {
  title: spotlight.title || upstream.spotlight_title,
  slug: spotlight.slug || upstream.spotlight_slug,
  article_url: upstream.articleUrl,
  launched_at: new Date().toISOString(),
  generated: true,
  tasks: campaignTasks,
};

return [{ json: {
  success: true,
  total_tasks: campaignTasks.length,
  campaign_title: staticData.spotlight_campaign.title,
  generated: true,
} }];
